import { useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import database from '../data';

const studentDetailsByStudent = database.student_details.reduce((map, record) => {
  map[record.studentId] = record;
  return map;
}, {});

function StudentsManagement() {
  const [searchText, setSearchText] = useState('');
  const [subjects, setSubjects] = useState(database.subjects);
  const [newSubjectId, setNewSubjectId] = useState('');
  const [newSubjectName, setNewSubjectName] = useState('');

  const filteredStudents = useMemo(() => {
    const query = searchText.trim().toLowerCase();
    return database.students
      .filter((student) => student.name.toLowerCase().includes(query))
      .map((student) => ({
        ...student,
        detail: studentDetailsByStudent[student.studentId] || { address: { street: '', city: '' } }
      }));
  }, [searchText]);

  const handleAddSubject = (event) => {
    event.preventDefault();
    if (!newSubjectId.trim() || !newSubjectName.trim()) return;

    const nextId = subjects.length > 0 ? Math.max(...subjects.map((item) => item.id)) + 1 : 1;
    setSubjects([
      ...subjects,
      { id: nextId, subjectId: newSubjectId.trim(), name: newSubjectName.trim() }
    ]);
    setNewSubjectId('');
    setNewSubjectName('');
  };

  return (
    <div className="container py-4">
      <h1 className="text-center mb-4">Students Management</h1>
      <div className="mb-4">
        <input
          type="text"
          className="form-control"
          placeholder="Enter student name to search ..."
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
        />
      </div>
      <div className="row">
        <div className="col-md-4 mb-4">
          <div className="card p-3">
            <h4>Subjects</h4>
            <div className="list-group list-group-flush mb-3">
              {subjects.map((subject) => (
                <a
                  key={subject.subjectId}
                  href="#"
                  className="list-group-item list-group-item-action text-start"
                  onClick={(event) => event.preventDefault()}
                >
                  {subject.name}
                </a>
              ))}
            </div>
            <form onSubmit={handleAddSubject}>
              <div className="mb-2">
                <input
                  type="text"
                  className="form-control"
                  placeholder="Enter SubjectId"
                  value={newSubjectId}
                  onChange={(e) => setNewSubjectId(e.target.value)}
                />
              </div>
              <div className="mb-2">
                <input
                  type="text"
                  className="form-control"
                  placeholder="Enter SubjectName"
                  value={newSubjectName}
                  onChange={(e) => setNewSubjectName(e.target.value)}
                />
              </div>
              <button type="submit" className="btn btn-secondary">Add</button>
            </form>
          </div>
        </div>
        <div className="col-md-8">
          <div className="card p-3">
            <h4>List of Students</h4>
            <div className="table-responsive">
              <table className="table table-striped table-bordered align-middle">
                <thead>
                  <tr>
                    <th>StudentId</th>
                    <th>Name</th>
                    <th>Age</th>
                    <th>Street</th>
                    <th>City</th>
                    <th>IsRegularStudent</th>
                    <th>View grades</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredStudents.length > 0 ? (
                    filteredStudents.map((student) => (
                      <tr key={student.studentId}>
                        <td>{student.studentId}</td>
                        <td>{student.name}</td>
                        <td>{student.age}</td>
                        <td>{student.detail.address.street}</td>
                        <td>{student.detail.address.city}</td>
                        <td>{student.isRegularStudent ? 'Fulltime' : 'Applicant'}</td>
                        <td>
                          <Link to={`/student/${student.studentId}`}>Grades</Link>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={7} className="text-center">No students found.</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
      <footer className="text-center mt-4 pt-3 border-top">Copyright by: HExxxxxx</footer>
    </div>
  );
}

export default StudentsManagement;
